import React, { useState, useEffect, useRef, useCallback } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import { useAuth } from '../App';
import api from '../api';
import { analyzeSymptoms, analyzeSymptomsFull, loadLiveDeficiencies } from '../engine/analyzer.js';

// Fix leaflet default icons
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl:       'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl:     'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

const I = ({ c, style }) => <i className={`fa-solid ${c}`} style={style} />;

// ── i18n / Translations ───────────────────────────────────────────────────────
const TRANSLATIONS = {
  en: {
    dashboard: 'MediHelp AI Nutrition Dashboard',
    hello: 'Hello',
    aiChat: 'AI Chat',
    history: 'History',
    hospitals: 'Hospitals',
    appointments: 'Appointments',
    medications: 'Medications',
    trends: 'Health Trends',
    profile: 'Profile',
    sos: 'SOS Emergency',
    darkMode: 'Dark mode',
    language: 'Language',
    bookAppointment: 'Book Appointment',
    addMedication: 'Add Medication',
    checkInteractions: 'Check Interactions',
    exportHistory: 'Export History',
    saveProfile: 'Save Profile',
    doctorName: 'Doctor / Specialist Name',
    hospitalName: 'Hospital',
    date: 'Appointment Date',
    time: 'Appointment Time',
    notes: 'Notes',
    drugName: 'Drug / Supplement Name',
    dosage: 'Dosage',
    frequency: 'Frequency',
    startDate: 'Start Date',
    endDate: 'End Date',
    noAppointments: 'No appointments yet. Book your first one!',
    noMedications: 'No medications added yet.',
    noHistory: 'No analyses saved yet. Chat with the AI to get started!',
    scheduled: 'Scheduled',
    completed: 'Completed',
    cancelled: 'Cancelled',
    cancel: 'Cancel',
    delete: 'Delete',
    edit: 'Edit',
    save: 'Save',
    close: 'Close',
    sendSOS: 'Send Emergency Alert',
    sosConfirm: 'This will alert emergency contacts and show nearest hospitals.',
    emergency: 'Emergency',
    feedbackHelpful: 'Was this helpful?',
    yes: 'Yes',
    no: 'No',
    engineUsed: 'Engine',
    total: 'Total Analyses',
    topConditions: 'Most Common Findings',
    last30Days: 'Activity — Last 30 Days',
  },
  sw: {
    dashboard: 'Dashibodi ya Afya ya MediHelp',
    hello: 'Habari',
    aiChat: 'Mazungumzo ya AI',
    history: 'Historia',
    hospitals: 'Hospitali',
    appointments: 'Miadi',
    medications: 'Dawa',
    trends: 'Mwelekeo wa Afya',
    profile: 'Wasifu',
    sos: 'Dharura ya SOS',
    darkMode: 'Hali ya giza',
    language: 'Lugha',
    bookAppointment: 'Weka Miadi',
    addMedication: 'Ongeza Dawa',
    checkInteractions: 'Angalia Mwingiliano',
    exportHistory: 'Hamisha Historia',
    saveProfile: 'Hifadhi Wasifu',
    doctorName: 'Jina la Daktari',
    hospitalName: 'Hospitali',
    date: 'Tarehe ya Miadi',
    time: 'Wakati wa Miadi',
    notes: 'Maelezo',
    drugName: 'Jina la Dawa',
    dosage: 'Kipimo',
    frequency: 'Mara ngapi',
    startDate: 'Tarehe ya Kuanza',
    endDate: 'Tarehe ya Kumalizia',
    noAppointments: 'Hakuna miadi bado. Weka ya kwanza!',
    noMedications: 'Hakuna dawa zilizoongezwa bado.',
    noHistory: 'Hakuna uchambuzi uliohifadhiwa bado.',
    scheduled: 'Imewekwa',
    completed: 'Imekamilika',
    cancelled: 'Imefutwa',
    cancel: 'Ghairi',
    delete: 'Futa',
    edit: 'Hariri',
    save: 'Hifadhi',
    close: 'Funga',
    sendSOS: 'Tuma Arifa ya Dharura',
    sosConfirm: 'Hii itatuma arifa kwa wasiliani wa dharura.',
    emergency: 'Dharura',
    feedbackHelpful: 'Je, hii ilisaidia?',
    yes: 'Ndio',
    no: 'Hapana',
    engineUsed: 'Injini',
    total: 'Jumla ya Uchambuzi',
    topConditions: 'Matokeo ya Kawaida',
    last30Days: 'Shughuli — Siku 30 Zilizopita',
  }
};

// ── Dark mode CSS ─────────────────────────────────────────────────────────────
const DARK_STYLE = `
  /* ── Base ── */
  .mh-dark, .mh-dark body { background:#0f172a!important; color:#f1f5f9!important; }
  .mh-dark * { color: inherit; }

  /* ── Cards / surfaces ── */
  .mh-dark .card,
  .mh-dark [class*="card"] { background:#1e293b!important; border-color:#334155!important; color:#f1f5f9!important; }

  /* ── App shell ── */
  .mh-dark .app-header,
  .mh-dark header { background:#1e293b!important; border-color:#334155!important; }
  .mh-dark .sidebar,
  .mh-dark nav { background:#1e293b!important; border-color:#334155!important; }
  .mh-dark .main-content,
  .mh-dark main { background:#0f172a!important; }

  /* ── Tabs ── */
  .mh-dark .tabs { background:#1e293b!important; border-color:#334155!important; }
  .mh-dark .tab { color:#94a3b8!important; background:transparent!important; }
  .mh-dark .tab.active { color:#4ade80!important; border-color:#4ade80!important; background:#0f172a!important; }
  .mh-dark .tab:hover:not(.active) { color:#e2e8f0!important; background:#334155!important; }

  /* ── Forms ── */
  .mh-dark .form-input,
  .mh-dark input,
  .mh-dark select,
  .mh-dark textarea { background:#0f172a!important; border-color:#334155!important; color:#f1f5f9!important; }
  .mh-dark input::placeholder,
  .mh-dark textarea::placeholder { color:#64748b!important; }
  .mh-dark label,
  .mh-dark .form-label { color:#94a3b8!important; }

  /* ── Buttons ── */
  .mh-dark .btn-ghost { color:#94a3b8!important; border-color:#334155!important; background:transparent!important; }
  .mh-dark .btn-ghost:hover { background:#334155!important; color:#f1f5f9!important; }
  .mh-dark .btn-outline { border-color:#334155!important; color:#94a3b8!important; }

  /* ── Alerts ── */
  .mh-dark .alert { background:#1e293b!important; border-color:#334155!important; color:#f1f5f9!important; }
  .mh-dark .alert-warning { background:#1c1a0a!important; border-color:#854d0e!important; color:#fde047!important; }
  .mh-dark .alert-danger  { background:#1c0a0a!important; border-color:#991b1b!important; color:#fca5a5!important; }
  .mh-dark .alert-success { background:#0a1c0a!important; border-color:#166534!important; color:#86efac!important; }

  /* ── Chatbot ── */
  .mh-dark .chatbox { background:#0f172a!important; border-color:#334155!important; }
  .mh-dark .chatbox > div:first-child,
  .mh-dark .chatbox > div:last-child { background:#1e293b!important; border-color:#334155!important; }
  .mh-dark .chatbox textarea { background:#0f172a!important; border-color:#334155!important; color:#f1f5f9!important; }
  /* AI message bubble */
  .mh-dark .chatbox .ai-bubble { background:#1e293b!important; border-color:#334155!important; color:#f1f5f9!important; }

  /* ── Def Cards ── */
  .mh-dark .def-card { background:#1e293b!important; }
  .mh-dark .def-card-body { background:#0f172a!important; }
  .mh-dark .def-card li,
  .mh-dark .def-card p { color:#cbd5e1!important; }
  .mh-dark .def-card strong { color:#f1f5f9!important; }

  /* ── History items ── */
  .mh-dark .history-item { background:#1e293b!important; border-color:#334155!important; }
  .mh-dark .history-item .history-detail { background:#0f172a!important; }

  /* ── Tables ── */
  .mh-dark table { background:#1e293b!important; }
  .mh-dark th { background:#0f172a!important; color:#94a3b8!important; border-color:#334155!important; }
  .mh-dark td { border-color:#334155!important; color:#f1f5f9!important; }
  .mh-dark tr:hover td { background:#334155!important; }

  /* ── Modals ── */
  .mh-dark .modal-backdrop { background:rgba(0,0,0,0.8)!important; }
  .mh-dark .modal-box { background:#1e293b!important; border-color:#334155!important; color:#f1f5f9!important; }

  /* ── Map sidebar list ── */
  .mh-dark .hospital-list-item { background:#1e293b!important; border-color:#334155!important; }
  .mh-dark .hospital-list-item:hover { background:#334155!important; }

  /* ── Misc text ── */
  .mh-dark h1,.mh-dark h2,.mh-dark h3,.mh-dark h4,.mh-dark h5,.mh-dark h6 { color:#f1f5f9!important; }
  .mh-dark p,.mh-dark span:not([class*="badge"]):not([class*="status"]) { color:#e2e8f0; }
  .mh-dark small,.mh-dark .text-muted { color:#64748b!important; }
  .mh-dark hr { border-color:#334155!important; }
  .mh-dark .divider { background:#334155!important; }

  /* ── Dropdown / select options ── */
  .mh-dark option { background:#1e293b; color:#f1f5f9; }

  /* ── Status badges keep their colours but with dark bg ── */
  .mh-dark .status-scheduled { background:#1e3a5f!important; color:#60a5fa!important; }
  .mh-dark .status-completed { background:#0a2e1a!important; color:#4ade80!important; }
  .mh-dark .status-cancelled { background:#2e0a0a!important; color:#f87171!important; }

  /* ── Scrollbar ── */
  .mh-dark ::-webkit-scrollbar { width:6px; }
  .mh-dark ::-webkit-scrollbar-track { background:#0f172a; }
  .mh-dark ::-webkit-scrollbar-thumb { background:#334155; border-radius:3px; }
`;

// ── Map fly-to helper ─────────────────────────────────────────────────────────
function FlyTo({ coords }) {
  const map = useMap();
  useEffect(() => { if (coords) map.flyTo(coords, 13, { duration: 1.2 }); }, [coords, map]);
  return null;
}

// ── Deficiency Result Card ────────────────────────────────────────────────────
const DEF_ICONS = {
  iron:'fa-droplet', vitamin_a:'fa-eye', vitamin_d:'fa-sun', vitamin_b12:'fa-brain',
  folate:'fa-seedling', iodine:'fa-shield-halved', zinc:'fa-shield', calcium:'fa-bone',
  vitamin_c:'fa-lemon', protein:'fa-dumbbell',
};

function DefCard({ r, analysisId, onFeedback }) {
  const [open, setOpen] = useState(false);
  const [fbSent, setFbSent] = useState(false);
  const iconClass = DEF_ICONS[r.id] || 'fa-circle-dot';

  const sendFeedback = async (helpful) => {
    try {
      await api.post('/api/feedback', { analysis_id: analysisId, predicted_id: r.id, helpful });
      setFbSent(true);
      if (onFeedback) onFeedback();
