// ── Chatbot ───────────────────────────────────────────────────────────────────
function Chatbot({ user }) {
  const makeWelcome = () => ({
    id:'w', type:'ai', results:null, analysisId:null,
    text:`Hello ${user?.name?.split(' ')[0]||'there'}!\n\nI'm MediHelp AI — your Kenya nutrition health assistant.\n\nDescribe your symptoms in plain language and I'll identify possible nutritional deficiencies with Kenyan food solutions.\n\n**Try:** "I feel tired all the time, my hair is falling out and I get dizzy"\n\nWhat symptoms are you experiencing?`
  });

  const [messages, setMessages] = useState([makeWelcome()]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [engineInfo, setEngineInfo] = useState('');
  const endRef = useRef(null);

  useEffect(()=>{ loadLiveDeficiencies(); },[]);
  useEffect(() => { endRef.current?.scrollIntoView({ behavior:'smooth' }); }, [messages, loading]);

  const send = async () => {
    const text = input.trim();
    if (!text || loading) return;
    setInput('');
    setMessages(m => [...m, { id:Date.now(), type:'user', text, results:null, analysisId:null }]);
    setLoading(true);
    await new Promise(r => setTimeout(r, 800));

    let results = analyzeSymptomsFull(text);
    let analysisId = null;
    let engine = 'rule_based';

    // Try backend (ML-powered) analysis
    try {
      const res = await api.post('/api/analyze', { symptoms: text });
      if (res.data.results?.length > 0) {
        results = res.data.results;
        engine = res.data.engine || 'backend';
        analysisId = null; // we'll fetch from history
      }
    } catch {
      // Non-critical — frontend rule-based already ran
      try { await api.post('/api/analyze', { symptoms: text }); } catch {}
    }

    setEngineInfo(engine === 'ml_naive_bayes' ? '🤖 ML (Naive Bayes)' : '📚 Rule-based');

    const reply = results.length > 0
      ? `I found **${results.length} potential deficiency risk${results.length>1?'s':''}** based on your symptoms.\n\nTop match: **${results[0].name}** (${results[0].confidence}% confidence).\n\nExpand each card below for Kenyan food remedies, tips, supplements and doctor guidance.`
      : `I didn't detect a specific nutritional deficiency from that — you might be asking a general health question, which is completely fine!\n\nFor the best results, describe **physical symptoms** you're experiencing. For example:\n\n• "I feel **tired**, look **pale**, dizzy" → Iron deficiency\n• "**Bone pain**, low mood, fatigue" → Vitamin D\n• "**Numbness** in hands/feet, forgetful" → Vitamin B12\n• "Child has **swollen belly**, slow growth" → Protein\n• "**Night blindness**, dry eyes" → Vitamin A\n\nWhat physical symptoms are you experiencing?`;

    setMessages(m => [...m, { id:Date.now()+1, type:'ai', text:reply, results, analysisId }]);
    setLoading(false);
  };

  const fmt = t => t.replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>').replace(/\n/g,'<br/>');

  return (
    <div style={{ display:'flex', flexDirection:'column', height:'calc(100vh - 230px)', minHeight:500, background:'#f9fafb', borderRadius:12, border:'1px solid #e5e7eb', overflow:'hidden' }} className="chatbox">
      {/* Header */}
      <div style={{ padding:'0.75rem 1rem', background:'white', borderBottom:'1px solid #e5e7eb', display:'flex', alignItems:'center', justifyContent:'space-between', flexShrink:0 }}>
        <div style={{ display:'flex', alignItems:'center', gap:8 }}>
          <div style={{ width:32, height:32, borderRadius:'50%', background:'linear-gradient(135deg,#16a34a,#15803d)', display:'flex', alignItems:'center', justifyContent:'center' }}>
            <I c="fa-stethoscope" style={{fontSize:'0.8rem', color:'white'}}/>
          </div>
          <div>
            <div style={{ fontWeight:700, fontSize:'0.875rem', color:'#111827' }}>MediHelp AI</div>
            <div style={{ fontSize:'0.7rem', color:'#16a34a', display:'flex', alignItems:'center', gap:4 }}>
              <span style={{ width:6, height:6, borderRadius:'50%', background:'#16a34a', display:'inline-block' }}/>
              Online {engineInfo && `· ${engineInfo}`}
            </div>
          </div>
        </div>
        <button onClick={()=>setMessages([makeWelcome()])} className="btn btn-ghost btn-sm" style={{fontSize:'0.72rem'}}>
          <I c="fa-rotate" style={{marginRight:4}}/>New Chat
        </button>
      </div>

      {/* Messages */}
      <div style={{ flex:1, overflowY:'auto', padding:'1rem', display:'flex', flexDirection:'column', gap:12 }}>
        {messages.map(msg => (
          <div key={msg.id} style={{ animation:'msgfade 0.3s ease' }}>
            <div style={{ display:'flex', gap:8, justifyContent:msg.type==='user'?'flex-end':'flex-start', alignItems:'flex-end' }}>
              {msg.type==='ai' && (
                <div style={{ width:28, height:28, borderRadius:'50%', background:'linear-gradient(135deg,#16a34a,#15803d)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, marginBottom:2 }}>
                  <I c="fa-stethoscope" style={{fontSize:'0.7rem', color:'white'}}/>
                </div>
              )}
              <div className={msg.type==='ai' ? 'ai-bubble' : ''} style={{ maxWidth:'78%', padding:'0.65rem 1rem', borderRadius:msg.type==='user'?'18px 18px 4px 18px':'18px 18px 18px 4px', background:msg.type==='user'?'linear-gradient(135deg,#16a34a,#15803d)':'white', color:msg.type==='user'?'white':'#111827', border:msg.type==='ai'?'1px solid #e5e7eb':'none', fontSize:'0.875rem', lineHeight:1.7, boxShadow:'0 1px 4px rgba(0,0,0,0.06)' }}>
                <span dangerouslySetInnerHTML={{ __html:fmt(msg.text) }}/>
              </div>
              {msg.type==='user' && (
                <div style={{ width:28, height:28, borderRadius:'50%', background:'#374151', display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontSize:'0.72rem', fontWeight:700, flexShrink:0, marginBottom:2 }}>
                  {(user?.name||'U')[0].toUpperCase()}
                </div>
              )}
            </div>
            {msg.results?.length > 0 && (
              <div style={{ marginTop:10, marginLeft:36 }}>
                {msg.results.map(r => <DefCard key={r.id} r={r} analysisId={msg.analysisId}/>)}
              </div>
            )}
          </div>
        ))}
        {loading && (
          <div style={{ display:'flex', gap:8, alignItems:'flex-end' }}>
            <div style={{ width:28, height:28, borderRadius:'50%', background:'linear-gradient(135deg,#16a34a,#15803d)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
              <I c="fa-stethoscope" style={{fontSize:'0.7rem', color:'white'}}/>
            </div>
            <div style={{ padding:'0.65rem 1rem', background:'white', border:'1px solid #e5e7eb', borderRadius:'18px 18px 18px 4px', display:'flex', gap:4, alignItems:'center' }}>
              {[0,1,2].map(i => <span key={i} style={{ width:7, height:7, background:'#16a34a', borderRadius:'50%', display:'inline-block', animation:`chatbounce 1.1s ease-in-out ${i*0.18}s infinite` }}/>)}
              <span style={{ marginLeft:8, fontSize:'0.78rem', color:'#6b7280', fontStyle:'italic' }}>Analysing symptoms...</span>
            </div>
          </div>
        )}
        <div ref={endRef}/>
      </div>

      {/* Input */}
      <div style={{ padding:'0.75rem 1rem', background:'white', borderTop:'1px solid #e5e7eb', flexShrink:0 }}>
        <div style={{ display:'flex', gap:8 }}>
          <textarea value={input} onChange={e=>setInput(e.target.value)}
            onKeyDown={e=>{ if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();send();} }}
            placeholder="Describe your symptoms... e.g. I feel tired, my hair is falling out and I get dizzy"
            rows={2} disabled={loading}
            style={{ flex:1, padding:'0.65rem 1rem', border:'1.5px solid #e5e7eb', borderRadius:10, fontFamily:'Outfit,sans-serif', fontSize:'0.875rem', resize:'none', outline:'none', lineHeight:1.5, transition:'border-color 0.18s', color:'#111827' }}
            onFocus={e=>e.target.style.borderColor='#16a34a'}
            onBlur={e=>e.target.style.borderColor='#e5e7eb'}
          />
          <button onClick={send} disabled={!input.trim()||loading} className="btn btn-primary" style={{ borderRadius:10, padding:'0 1.25rem', flexShrink:0, gap:6 }}>
            <I c="fa-paper-plane"/>
          </button>
        </div>
        <div style={{ fontSize:'0.68rem', color:'#9ca3af', marginTop:5 }}>
          Press Enter to send · AI guidance only · Not a substitute for medical advice
        </div>
      </div>
      <style>{`
        @keyframes chatbounce { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-5px)} }
        @keyframes msgfade    { from{opacity:0;transform:translateY(6px)} to{opacity:1;transform:translateY(0)} }
      `}</style>
    </div>
  );
}

